#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int R1, W1, C1, R2, W2, C2;
        scanf("%d %d %d", &R1, &W1, &C1);
        scanf("%d %d %d", &R2, &W2, &C2);
        int aWin = 0, bWin = 0;
        if (R1 > R2) aWin++; else bWin++;
        if (W1 > W2) aWin++; else bWin++;
        if (C1 > C2) aWin++; else bWin++;
        if (aWin > bWin) printf("A\n");
        else printf("B\n");
    }
    return 0;
}

