public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int t = 0; t < T; t++) {
            StringTokenizer stA = new StringTokenizer(br.readLine());
            int R1 = Integer.parseInt(stA.nextToken());
            int W1 = Integer.parseInt(stA.nextToken());
            int C1 = Integer.parseInt(stA.nextToken());
            StringTokenizer stB = new StringTokenizer(br.readLine());
            int R2 = Integer.parseInt(stB.nextToken());
            int W2 = Integer.parseInt(stB.nextToken());
            int C2 = Integer.parseInt(stB.nextToken());
            int aWin = 0, bWin = 0;
            if (R1 > R2) aWin++; else bWin++;
            if (W1 > W2) aWin++; else bWin++;
